INSERT INTO `jobs` (`id`, `user_id`, `category_id`, `title`, `location`, `company_name`, `salary`, `openings`, `min_age`, `max_age`, `gender_preference`, `category`, `job_type_tags`, `is_walkin`, `interview_slot`, `payout_amount`, `minimum_stay_days`, `education_required`, `job_type`, `description`, `min_experience`, `max_experience`, `skills_required`, `application_deadline`, `company_website`, `status`, `partner_visibility`, `created_at`, `updated_at`, `experience_level_id`, `education_level_id`) VALUES
(7, 28, 1, 'java developer', 'Mumbai', 'Nimbus Technologies', '35k - 50k', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, 'Full-time', 'NimbusLogic Technologies Pvt. Ltd. is a fast-growing software solutions company headquartered in Bangalore, India, with satellite development hubs in Pune and Hyderabad. We specialize in building scalable enterprise applications, cloud-native platforms, and AI-driven business automation tools for clients across fintech, e-commerce, healthtech, and logistics industries.\r\n\r\nWith a culture built on innovation, long-term thinking, and a healthy obsession with clean code, NimbusLogic fosters an environment where developers grow fast, solve real problems, and see their work impact millions of end-users worldwide. If you love learning, experimenting, and building software that doesn’t break on a Monday morning — you’ll vibe perfectly here.\r\n\r\nRole: Java Developer\r\n\r\nWe’re looking for a passionate Java Developer who enjoys solving complex technical challenges and writing clean, maintainable code. In this role, you’ll collaborate with cross-functional teams to design, build, test, and deploy high-performance backend systems and microservices used in production at scale.\r\n\r\nResponsibilities:\r\n\r\nDevelop, maintain, and enhance backend applications using Java (8+), Spring Boot, and related frameworks.\r\n\r\nDesign and implement RESTful APIs and microservices architecture.\r\n\r\nWrite clean, efficient, testable code following best practices and design patterns.\r\n\r\nWork closely with DevOps, product, and QA teams to ensure high-quality deliverables.\r\n\r\nOptimize application performance, scalability, and security.\r\n\r\nParticipate in code reviews, sprint planning, and architectural discussions.\r\n\r\nDebug production issues and contribute to improving system reliability.', NULL, NULL, 'Bachelor’s degree in Computer Science, Engineering, or equivalent experience.\r\n\r\n2–5 years of hands-on experience in backend development using Java.\r\n\r\nStrong knowledge of Spring Boot, Hibernate/JPA, Maven/Gradle, and REST APIs.\r\n\r\nExperience with relational databases (MySQL/PostgreSQL) and query optimization.\r\n\r\nUnderstanding of microservices architecture and distributed systems.\r\n\r\nFamiliarity with Git, CI/CD pipelines, Docker/Kubernetes (preferred).\r\n\r\nStrong problem-solving, analytical thinking, and debugging skills.', '2025-12-18', 'https://www.nimbustech.com', 'approved', 'all', '2025-12-08 10:36:53', '2025-12-08 11:11:25', NULL, NULL),
(8, 28, 8, 'Designer', 'Mumbai', 'Nimbus Technologies', '35k - 50k', 11, 24, 50, 'Female', 'Designer', '[\"Walkin\",\"New\"]', 1, '2025-12-19 10:30:00', 2000.00, 30, NULL, 'Full-time', 'NimbusLogic Technologies Pvt. Ltd. is a fast-growing software solutions company headquartered in Bangalore, India, with satellite development hubs in Pune and Hyderabad. We specialize in building scalable enterprise applications, cloud-native platforms, and AI-driven business automation tools for clients across fintech, e-commerce, healthtech, and logistics industries.\r\n\r\nWith a culture built on innovation, long-term thinking, and a healthy obsession with clean code, NimbusLogic fosters an environment where developers grow fast, solve real problems, and see their work impact millions of end-users worldwide. If you love learning, experimenting, and building software that doesn’t break on a Monday morning — you’ll vibe perfectly here.\r\n\r\nRole: Java Developer\r\n\r\nWe’re looking for a passionate Java Developer who enjoys solving complex technical challenges and writing clean, maintainable code. In this role, you’ll collaborate with cross-functional teams to design, build, test, and deploy high-performance backend systems and microservices used in production at scale.\r\n\r\nResponsibilities:\r\n\r\nDevelop, maintain, and enhance backend applications using Java (8+), Spring Boot, and related frameworks.\r\n\r\nDesign and implement RESTful APIs and microservices architecture.\r\n\r\nWrite clean, efficient, testable code following best practices and design patterns.\r\n\r\nWork closely with DevOps, product, and QA teams to ensure high-quality deliverables.\r\n\r\nOptimize application performance, scalability, and security.\r\n\r\nParticipate in code reviews, sprint planning, and architectural discussions.\r\n\r\nDebug production issues and contribute to improving system reliability.', NULL, NULL, 'Strong knowledge of Spring Boot, Hibernate/JPA, Maven/Gradle, and REST APIs.\r\n\r\nExperience with relational databases (MySQL/PostgreSQL) and query optimization.\r\n\r\nUnderstanding of microservices architecture and distributed systems.\r\n\r\nFamiliarity with Git, CI/CD pipelines, Docker/Kubernetes (preferred).\r\n\r\nStrong problem-solving, analytical thinking, and debugging skills.', '2025-12-26', 'https://www.nimbustech.com', 'on_hold', 'all', '2025-12-08 13:41:29', '2025-12-20 00:15:24', 3, 4),
